class Solution:
    def firstDayBeenInAllRooms(self, nextVisit):
        MOD = 10 ** 9 + 7
        n = len(nextVisit)
        visits = [0] * n
        visited_count = 0
        cur = 0
        day = 0
        while True:
            visits[cur] += 1
            if visits[cur] == 1:
                visited_count += 1
            if visited_count == n:
                return day % MOD
            day += 1
            if visits[cur] % 2 == 1:
                cur = nextVisit[cur]
            else:
                cur = (cur + 1) % n

