class Solution:
    def firstDayBeenInAllRooms(self, nextVisit):
        MOD = 10 ** 9 + 7
        n = len(nextVisit)
        first_day = [0] * n
        for i in range(1, n):
            first_day[i] = (2 * first_day[i - 1] - first_day[nextVisit[i - 1]] + 2) % MOD
        return first_day[-1] % MOD

