var firstDayBeenInAllRooms = function(nextVisit) {
    const MOD = 1000000007;
    const n = nextVisit.length;
    const firstDay = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        let v = (2 * firstDay[i - 1] - firstDay[nextVisit[i - 1]] + 2) % MOD;
        if (v < 0) v += MOD;
        firstDay[i] = v;
    }
    return firstDay[n - 1] % MOD;
};
